+        int size = 5;
+
+        {
+            byte[] buf = new byte[size*2];
+            DataBuffer db = new DataBufferByte(buf, size);
+            test(db, size);
+            test(db, -1);
+            db = new DataBufferByte(buf, size-1, 1);
+            test(db, size);
